/*
 * aquarium_controller.ino — Smart Aquarium Controller
 *
 * Elements:
 *   1. DS18B20 1-Wire Temperature Probe — water temperature every 5 s
 *   2. DS3231 RTC Alarm Scheduling     — lights on 08:00, off 22:00
 *   3. N-Channel MOSFET load switch    — D5 lights, D6 pump
 *   4. SSD1306 OLED Display            — live temp + status
 *   5. Arduino Nano MCU                — orchestrator
 */

#include <OneWire.h>
#include <DallasTemperature.h>
#include <RTClib.h>
#include <Wire.h>
#include <Adafruit_SSD1306.h>

// --- Pin assignments ---
#define ONE_WIRE_BUS  2
#define LIGHTS_PIN    5
#define PUMP_PIN      6
#define BUZZER_PIN    7
#define RTC_INT_PIN   3   // INT0

// --- Constants ---
#define SETPOINT_C     25.0f
#define ALARM_DELTA_C   2.0f
#define POLL_MS      5000UL
#define DISPLAY_MS   2000UL

// --- Objects ---
OneWire ow(ONE_WIRE_BUS);
DallasTemperature sensors(&ow);
RTC_DS3231 rtc;
Adafruit_SSD1306 oled(128, 64, &Wire, -1);

float last_temp   = SETPOINT_C;
bool  lights_on   = false;
bool  pump_on     = false;

volatile bool rtc_alarm = false;
void on_rtc_int() { rtc_alarm = true; }

void update_oled() {
  oled.clearDisplay();
  oled.setTextSize(1);
  oled.setTextColor(SSD1306_WHITE);
  oled.setCursor(0, 0);
  oled.printf("Temp: %.1f/%.0f C", last_temp, SETPOINT_C);
  oled.setCursor(0, 20);
  oled.printf("Lights: %s", lights_on ? "ON " : "OFF");
  oled.setCursor(0, 36);
  oled.printf("Pump:   %s", pump_on   ? "ON " : "OFF");
  oled.display();
}

void setup() {
  Serial.begin(115200);
  Wire.begin();

  // Peripherals
  sensors.begin();
  sensors.setResolution(12);
  rtc.begin();

  // OLED
  oled.begin(SSD1306_SWITCHCAPVCC, 0x3C);
  oled.clearDisplay();
  oled.display();

  // Output pins
  pinMode(LIGHTS_PIN, OUTPUT); digitalWrite(LIGHTS_PIN, LOW);
  pinMode(PUMP_PIN,   OUTPUT); digitalWrite(PUMP_PIN,   LOW);
  pinMode(BUZZER_PIN, OUTPUT); digitalWrite(BUZZER_PIN, LOW);

  // RTC alarms
  rtc.clearAlarm(1); rtc.clearAlarm(2);
  rtc.setAlarm1(DateTime(0,0,0,8,0,0),  DS3231_A1_Hour); // 08:00 lights on
  rtc.setAlarm2(DateTime(0,0,0,22,0,0), DS3231_A2_Hour); // 22:00 lights off
  rtc.writeSqwPinMode(DS3231_OFF);
  rtc.disableAlarm(1); rtc.disableAlarm(2);
  rtc.clearAlarm(1); rtc.clearAlarm(2);
  // Re-enable alarms so INT fires
  Wire.beginTransmission(0x68);
  Wire.write(0x0E); Wire.write(0x05); // INTCN=1, A1IE=1, A2IE=0 for alarm 1
  Wire.endTransmission();

  pinMode(RTC_INT_PIN, INPUT_PULLUP);
  attachInterrupt(digitalPinToInterrupt(RTC_INT_PIN), on_rtc_int, FALLING);

  Serial.println(F("Aquarium controller ready."));
}

static uint8_t alarm_miss_count = 0;

void loop() {
  static unsigned long last_poll    = 0;
  static unsigned long last_display = 0;
  static uint8_t alarm_consec       = 0;

  unsigned long now = millis();

  // --- 1. Temperature poll ---
  if (now - last_poll >= POLL_MS) {
    last_poll = now;
    sensors.requestTemperatures();
    last_temp = sensors.getTempCByIndex(0);
    if (fabsf(last_temp - SETPOINT_C) > ALARM_DELTA_C) {
      alarm_consec++;
      if (alarm_consec >= 3) {
        digitalWrite(BUZZER_PIN, HIGH);
        Serial.printf("ALARM: %.1f C  (setpoint %.0f)\n", last_temp, SETPOINT_C);
      }
    } else {
      alarm_consec = 0;
      digitalWrite(BUZZER_PIN, LOW);
    }
  }

  // --- 2. RTC alarm handling ---
  if (rtc_alarm) {
    rtc_alarm = false;
    DateTime now_dt = rtc.now();
    if (rtc.alarmFired(1)) {
      lights_on = true;
      pump_on   = true;  // brief top-off: timed below
      digitalWrite(LIGHTS_PIN, HIGH);
      digitalWrite(PUMP_PIN, HIGH);
      delay(30000);          // run top-off pump for 30 s
      pump_on = false;
      digitalWrite(PUMP_PIN, LOW);
      rtc.clearAlarm(1);
    }
    if (rtc.alarmFired(2)) {
      lights_on = false;
      digitalWrite(LIGHTS_PIN, LOW);
      rtc.clearAlarm(2);
    }
    Serial.printf("RTC alarm at %02d:%02d\n", now_dt.hour(), now_dt.minute());
  }

  // --- 3. OLED refresh ---
  if (now - last_display >= DISPLAY_MS) {
    last_display = now;
    update_oled();
  }
}
